// 拼音字体（TeXGyreAdventor）的 data URI，base64 内嵌（约 227KB）
export const PINYIN_FONT_URI = 'data:font/otf;base64,';

export const FONT_LIST = [
    ['LXGWWenKai', './fonts/LXGWWenKai-Regular.ttf'],
    ['LXGWWenKaiLight', './fonts/LXGWWenKai-Light.ttf'],
    ['SourceHanSerifSC', './fonts/SourceHanSerifSC-Regular.otf'],
    ['TW-Kai', './fonts/TW-Kai.ttf'],
    ['TeXGyreAdventor', PINYIN_FONT_URI]
];

let customFontCounter = 0;

export async function loadFonts() {
    for (const [name, url] of FONT_LIST) {
        try {
            const ff = new FontFace(name, 'url(' + url + ')');
            await ff.load();
            document.fonts.add(ff);
        } catch(e) { console.warn('字体加载失败: ' + name); }
    }
    console.log('FontFace loading complete');
}

export function handleFontUpload(file) {
    if (!file) return;
    customFontCounter++;
    const fontName = 'CustomFont' + customFontCounter;
    const displayName = file.name.replace(/\.(ttf|otf|woff|woff2)$/i, '');
    const reader = new FileReader();
    reader.onload = function(ev) {
        var fontFace = new FontFace(fontName, 'url(' + ev.target.result + ')');
        fontFace.load().then(function(loaded) {
            document.fonts.add(loaded);
            var select = document.getElementById('font-select');
            var opt = document.createElement('option');
            opt.value = fontName;
            opt.textContent = '★ ' + displayName;
            opt.selected = true;
            select.appendChild(opt);
            console.log('自定义字体已加载: ' + displayName);
        }).catch(function(err) {
            alert('字体加载失败: ' + err.message);
        });
    };
    reader.readAsDataURL(file);
}